async function fetchAll(urls, options = {}) {
  // Input validation
  if (!Array.isArray(urls)) {
    throw new TypeError('urls must be an array');
  }

  if (urls.length === 0) {
    return [];
  }

  const {
    timeout = 10000,
    concurrency = Infinity,
    validateUrl = null
  } = options;

  // Validate URLs if validation function provided
  if (validateUrl) {
    urls = urls.filter(url => validateUrl(url));
  }

  // Create fetch promises with timeout and error handling
  const fetchWithTimeout = async (url) => {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
      const response = await fetch(url, { signal: controller.signal });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText} for ${url}`);
      }

      const data = await response.json();
      return { url, data, error: null };
    } catch (error) {
      return { url, data: null, error: error.message };
    } finally {
      clearTimeout(timeoutId);
    }
  };

  // Process with concurrency limit
  if (concurrency === Infinity || concurrency >= urls.length) {
    // Parallel execution
    return Promise.all(urls.map(fetchWithTimeout));
  } else {
    // Limited concurrency (you'd need a more sophisticated implementation)
    // This is a simplified version
    const results = [];
    for (let i = 0; i < urls.length; i += concurrency) {
      const batch = urls.slice(i, i + concurrency);
      const batchResults = await Promise.all(batch.map(fetchWithTimeout));
      results.push(...batchResults);
    }
    return results;
  }
}

